在 verifySignature 方法中添加时间戳验证：

verifySignature(timestamp: string, body: string, signature: string): boolean {
  // 验证时间戳（5 分钟内有效）
  const requestTime = parseInt(timestamp);
  const now = Date.now();
  if (Math.abs(now - requestTime) > 300000) {
    this.logger.warn(`时间戳过期: ${timestamp}`);
    return false;
  }

  const expectedSignature = crypto
    .createHmac('sha256', this.webhookSecret)
    .update(timestamp + body)
    .digest('hex');

  return crypto.timingSafeEqual(
    Buffer.from(expectedSignature),
    Buffer.from(signature)
  );
}

使用 Redis 分布式锁：

private async getAccessToken(advertiserId: string): Promise<string> {
  const cacheKey = `ocean_engine:token:${advertiserId}`;
  let token = await this.redis.get(cacheKey);

  if (!token) {
    const lockKey = `ocean_engine:token_lock:${advertiserId}`;
    const lockValue = Date.now().toString();

    // 尝试获取锁（10 秒超时）
    const locked = await this.redis.set(lockKey, lockValue, 'EX', 10, 'NX');

    if (locked) {
      try {
        token = await this.refreshAccessToken(advertiserId);
      } finally {
        await this.redis.del(lockKey);
      }
    } else {
      // 等待其他请求刷新完成
      await new Promise(resolve => setTimeout(resolve, 100));
      token = await this.redis.get(cacheKey);
      if (!token) {
        throw new Error('Token 刷新失败');
      }
    }
  }

  return token;
}

修改 pollTaskStatus 方法，接收 job 对象：

async pollTaskStatus(taskId: string, attemptsMade: number): Promise<void> {
  const task = await this.findOne(taskId);

  if (
    task.status === DiagnosisStatus.SUCCESS ||
    task.status === DiagnosisStatus.FAILED ||
    task.status === DiagnosisStatus.TIMEOUT
  ) {
    return;
  }

  try {
    const result = await this.oceanEngineService.getDiagnosisTaskStatus(
      task.advertiserId,
      task.oceanTaskId,
    );

    if (result.status === 'SUCCESS') {
      await this.updateStatus(taskId, DiagnosisStatus.SUCCESS, result.result);
    } else if (result.status === 'FAILED') {
      await this.updateStatus(taskId, DiagnosisStatus.FAILED, null, result.error_message);
    } else if (result.status === 'PROCESSING') {
      await this.updateStatus(taskId, DiagnosisStatus.PROCESSING);
      throw new Error('任务处理中，继续轮询');
    }
  } catch (error) {
    if (attemptsMade >= 11) {
      await this.updateStatus(taskId, DiagnosisStatus.TIMEOUT, null, '任务超时');
    } else {
      throw error;
    }
  }
}

