private sanitizeErrorData(data: any): any {
  const sensitive = ['access_token', 'refresh_token', 'secret', 'password'];
  const sanitized = { ...data };
  sensitive.forEach(key => {
    if (sanitized[key]) {
      sanitized[key] = '***';
    }
  });
  return sanitized;
}

